import { buildLocalizeFn } from "../../_lib/buildLocalizeFn.js";

const eraValues = {
  narrow: ["ЩӮ", "ШЁ"],
  abbreviated: ["ЩӮ.Щ….", "ШЁ.Щ…."],
  wide: ["ЩӮШЁЩ„ Ш§ШІ Щ…ЫҢЩ„Ш§ШҜ", "ШЁШ№ШҜ Ш§ШІ Щ…ЫҢЩ„Ш§ШҜ"],
};

const quarterValues = {
  narrow: ["1", "2", "3", "4"],
  abbreviated: ["ШівҖҢЩ…1", "ШівҖҢЩ…2", "ШівҖҢЩ…3", "ШівҖҢЩ…4"],
  wide: ["ШіЩҮвҖҢЩ…Ш§ЩҮЩҮ 1", "ШіЩҮвҖҢЩ…Ш§ЩҮЩҮ 2", "ШіЩҮвҖҢЩ…Ш§ЩҮЩҮ 3", "ШіЩҮвҖҢЩ…Ш§ЩҮЩҮ 4"],
};

// Note: in English, the names of days of the week and months are capitalized.
// If you are making a new locale based on this one, check if the same is true for the language you're working on.
// Generally, formatted dates should look like they are in the middle of a sentence,
// e.g. in Spanish language the weekdays and months should be in the lowercase.
const monthValues = {
  narrow: ["Ъҳ", "ЩҒ", "Щ…", "Шў", "Щ…", "Ш¬", "Ш¬", "Шў", "Ші", "Ш§", "ЩҶ", "ШҜ"],
  abbreviated: [
    "ЪҳШ§ЩҶЩҖ",
    "ЩҒЩҲШұ",
    "Щ…Ш§ШұШі",
    "ШўЩҫШұ",
    "Щ…ЫҢ",
    "Ш¬ЩҲЩҶ",
    "Ш¬ЩҲЩ„ЩҖ",
    "ШўЪҜЩҲ",
    "ШіЩҫШӘЩҖ",
    "Ш§Ъ©ШӘЩҖ",
    "ЩҶЩҲШ§Щ…ЩҖ",
    "ШҜШіШ§Щ…ЩҖ",
  ],

  wide: [
    "ЪҳШ§ЩҶЩҲЫҢЩҮ",
    "ЩҒЩҲШұЫҢЩҮ",
    "Щ…Ш§ШұШі",
    "ШўЩҫШұЫҢЩ„",
    "Щ…ЫҢ",
    "Ш¬ЩҲЩҶ",
    "Ш¬ЩҲЩ„Ш§ЫҢ",
    "ШўЪҜЩҲШіШӘ",
    "ШіЩҫШӘШ§Щ…ШЁШұ",
    "Ш§Ъ©ШӘШЁШұ",
    "ЩҶЩҲШ§Щ…ШЁШұ",
    "ШҜШіШ§Щ…ШЁШұ",
  ],
};

const dayValues = {
  narrow: ["ЫҢ", "ШҜ", "Ші", "ЪҶ", "Щҫ", "Ш¬", "Шҙ"],
  short: ["1Шҙ", "2Шҙ", "3Шҙ", "4Шҙ", "5Шҙ", "Ш¬", "Шҙ"],
  abbreviated: [
    "ЫҢЪ©ШҙЩҶШЁЩҮ",
    "ШҜЩҲШҙЩҶШЁЩҮ",
    "ШіЩҮвҖҢШҙЩҶШЁЩҮ",
    "ЪҶЩҮШ§ШұШҙЩҶШЁЩҮ",
    "ЩҫЩҶШ¬ШҙЩҶШЁЩҮ",
    "Ш¬Щ…Ш№ЩҮ",
    "ШҙЩҶШЁЩҮ",
  ],

  wide: ["ЫҢЪ©ШҙЩҶШЁЩҮ", "ШҜЩҲШҙЩҶШЁЩҮ", "ШіЩҮвҖҢШҙЩҶШЁЩҮ", "ЪҶЩҮШ§ШұШҙЩҶШЁЩҮ", "ЩҫЩҶШ¬ШҙЩҶШЁЩҮ", "Ш¬Щ…Ш№ЩҮ", "ШҙЩҶШЁЩҮ"],
};

const dayPeriodValues = {
  narrow: {
    am: "ЩӮ",
    pm: "ШЁ",
    midnight: "ЩҶ",
    noon: "Шё",
    morning: "Шө",
    afternoon: "ШЁ.Шё.",
    evening: "Ш№",
    night: "Шҙ",
  },
  abbreviated: {
    am: "ЩӮ.Шё.",
    pm: "ШЁ.Шё.",
    midnight: "ЩҶЫҢЩ…ЩҮвҖҢШҙШЁ",
    noon: "ШёЩҮШұ",
    morning: "ШөШЁШӯ",
    afternoon: "ШЁШ№ШҜШ§ШІШёЩҮШұ",
    evening: "Ш№ШөШұ",
    night: "ШҙШЁ",
  },
  wide: {
    am: "ЩӮШЁЩ„вҖҢШ§ШІШёЩҮШұ",
    pm: "ШЁШ№ШҜШ§ШІШёЩҮШұ",
    midnight: "ЩҶЫҢЩ…ЩҮвҖҢШҙШЁ",
    noon: "ШёЩҮШұ",
    morning: "ШөШЁШӯ",
    afternoon: "ШЁШ№ШҜШ§ШІШёЩҮШұ",
    evening: "Ш№ШөШұ",
    night: "ШҙШЁ",
  },
};

const formattingDayPeriodValues = {
  narrow: {
    am: "ЩӮ",
    pm: "ШЁ",
    midnight: "ЩҶ",
    noon: "Шё",
    morning: "Шө",
    afternoon: "ШЁ.Шё.",
    evening: "Ш№",
    night: "Шҙ",
  },
  abbreviated: {
    am: "ЩӮ.Шё.",
    pm: "ШЁ.Шё.",
    midnight: "ЩҶЫҢЩ…ЩҮвҖҢШҙШЁ",
    noon: "ШёЩҮШұ",
    morning: "ШөШЁШӯ",
    afternoon: "ШЁШ№ШҜШ§ШІШёЩҮШұ",
    evening: "Ш№ШөШұ",
    night: "ШҙШЁ",
  },
  wide: {
    am: "ЩӮШЁЩ„вҖҢШ§ШІШёЩҮШұ",
    pm: "ШЁШ№ШҜШ§ШІШёЩҮШұ",
    midnight: "ЩҶЫҢЩ…ЩҮвҖҢШҙШЁ",
    noon: "ШёЩҮШұ",
    morning: "ШөШЁШӯ",
    afternoon: "ШЁШ№ШҜШ§ШІШёЩҮШұ",
    evening: "Ш№ШөШұ",
    night: "ШҙШЁ",
  },
};

const ordinalNumber = (dirtyNumber, _options) => {
  return String(dirtyNumber);
};

export const localize = {
  ordinalNumber,

  era: buildLocalizeFn({
    values: eraValues,
    defaultWidth: "wide",
  }),

  quarter: buildLocalizeFn({
    values: quarterValues,
    defaultWidth: "wide",
    argumentCallback: (quarter) => quarter - 1,
  }),

  month: buildLocalizeFn({
    values: monthValues,
    defaultWidth: "wide",
  }),

  day: buildLocalizeFn({
    values: dayValues,
    defaultWidth: "wide",
  }),

  dayPeriod: buildLocalizeFn({
    values: dayPeriodValues,
    defaultWidth: "wide",
    formattingValues: formattingDayPeriodValues,
    defaultFormattingWidth: "wide",
  }),
};
